            color: red;
            font-weight: bold;
        }
    </style>
</head>
<body>
    <h1>Singly Linked List Visualizer</h1>
    <p>This tool allows you to interact with a singly linked list. Enter a value (e.g., a number) and use the buttons to manipulate the list.</p>

    <div id="controls">
        <label for="value-input">Enter Value:</label>
        <input type="text" id="value-input" placeholder="e.g., 5">

        <button id="insert-head">Insert at Head</button>
        <button id="insert-tail">Insert at Tail</button>
        <button id="delete-value">Delete by Value</button>
        <button id="search-value">Search and Highlight</button>

        <div id="message" class="error"></div> <!-- For displaying messages like errors -->
    </div>

    <div id="list-container">
        <p id="empty-message">The list is empty.</p> <!-- Default message for empty list -->
    </div>

    <script>
        // Singly Linked List Class
        class Node {
            constructor(value) {
                this.value = value;
                this.next = null;
            }
        }

        class SinglyLinkedList {
            constructor() {
                this.head = null;
            }

            // Insert at Head
            insertAtHead(value) {
                const newNode = new Node(value);
                newNode.next = this.head;
                this.head = newNode;
            }

            // Insert at Tail
            insertAtTail(value) {
                const newNode = new Node(value);
                if (!this.head) {
                    this.head = newNode;
                    return;
                }
                let current = this.head;
                while (current.next) {
                    current = current.next;
                }
                current.next = newNode;
            }

            // Delete by Value (removes the first occurrence)
            deleteByValue(value) {
                if (!this.head) return false; // Empty list
                if (this.head.value === value) {
                    this.head = this.head.next;
                    return true;
                }
                let current = this.head;
                while (current.next) {
                    if (current.next.value === value) {
                        current.next = current.next.next;
                        return true;
                    }
                    current = current.next;
                }
                return false; // Value not found
            }

            // Search for Value (returns the first node with the value, or null)
            search(value) {
                let current = this.head;
                while (current) {
                    if (current.value == value) {
                        return current;
                    }
                    current = current.next;
                }
                return null; // Not found
            }

            // Get the list as an array for rendering
            toArray() {
                const array = [];
                let current = this.head;
                while (current) {
                    array.push(current.value);
                    current = current.next;
                }
                return array;
            }
        }

        // Initialize the linked list
        const linkedList = new SinglyLinkedList();
        const listContainer = document.getElementById('list-container');
        const emptyMessage = document.getElementById('empty-message');
        const messageDiv = document.getElementById('message');
        const valueInput = document.getElementById('value-input');

        // Function to render the linked list
        function renderList(highlightValue = null) {
            const values = linkedList.toArray();
            listContainer.innerHTML = ''; // Clear existing content
            emptyMessage.style.display = values.length === 0 ? 'block' : 'none'; // Show empty message if needed

            if (values.length > 0) {
                values.forEach((value, index) => {
                    const nodeDiv = document.createElement('div');
                    nodeDiv.className = 'node';
                    nodeDiv.textContent = value;

                    // Add highlight if this is the searched value
                    if (value == highlightValue) {
                        nodeDiv.classList.add('highlighted');
                    }

                    listContainer.appendChild(nodeDiv);

                    // Add arrow if it's not the last node
                    if (index < values.length - 1) {
                        const arrowDiv = document.createElement('div');
                        arrowDiv.className = 'arrow';
                        arrowDiv.textContent = '→'; // Unicode arrow
                        listContainer.appendChild(arrowDiv);
                    }
                });
            }
        }

        // Event listeners for buttons
        document.getElementById('insert-head').addEventListener('click', () => {
            const value = valueInput.value.trim();
            if (value === '') {
                messageDiv.textContent = 'Please enter a value.';
                return;
            }
            linkedList.insertAtHead(value);
            renderList();
            messageDiv.textContent = ''; // Clear any error messages
            valueInput.value = ''; // Clear input
        });

        document.getElementById('insert-tail').addEventListener('click', () => {
            const value = valueInput.value.trim();
            if (value === '') {
                messageDiv.textContent = 'Please enter a value.';
                return;
            }
            linkedList.insertAtTail(value);
            renderList();
            messageDiv.textContent = '';
            valueInput.value = '';
        });

        document.getElementById('delete-value').addEventListener('click', () => {
            const value = valueInput.value.trim();
            if (value === '') {
                messageDiv.textContent = 'Please enter a value.';
                return;
            }
            const success = linkedList.deleteByValue(value);
            if (success) {
                messageDiv.textContent = `Value '${value}' deleted.`;
            } else {
                messageDiv.textContent = `Value '${value}' not found.`;
            }
            renderList();
            valueInput.value = '';
        });

        document.getElementById('search-value').addEventListener('click', () => {
            const value = valueInput.value.trim();
            if (value === '') {
                messageDiv.textContent = 'Please enter a value.';
                return;
            }
            const foundNode = linkedList.search(value);
            if (foundNode) {
                messageDiv.textContent = `Value '${value}' found!`;
                renderList(value); // Re-render with highlight
            } else {
                messageDiv.textContent = `Value '${value}' not found.`;
                renderList(); // Re-render without highlight
            }
            valueInput.value = '';
        });

        // Initial render
        renderList();
    </script>
</body>
</html>
```

