                    setTimeout(() => {
                        nodes[foundIndex].classList.remove('highlighted');  // Remove highlight after 2 seconds
                    }, 2000);
                } else {
                    alert('Value not found in the list.');
                }
                document.getElementById('value-input').value = '';  // Clear input
            } else {
                alert('Please enter a value.');
            }
