    <h1>Linked List Visualization</h1>
    <p>Perform operations on the linked list below. Nodes are represented as boxes with arrows connecting them.</p>

    <div id="controls">
        <h3>Insert at Head: <input type="number" id="insertHeadValue" placeholder="Value"> <button onclick="insertAtHead()">Insert</button></h3>
        <h3>Insert at Tail: <input type="number" id="insertTailValue" placeholder="Value"> <button onclick="insertAtTail()">Insert</button></h3>
        <h3>Delete by Value: <input type="number" id="deleteValue" placeholder="Value"> <button onclick="deleteByValue()">Delete</button></h3>
        <h3>Search by Value: <input type="number" id="searchValue" placeholder="Value"> <button onclick="searchValue()">Search</button></h3>
    </div>

    <div id="linkedList">
        <!-- Linked list will be rendered here -->
    </div>

