        // Linked List Class
        class Node {
            constructor(value) {
                this.value = value;
                this.next = null;
            }
        }

        class LinkedList {
            constructor() {
                this.head = null;
            }

            insertAtHead(value) {
                const newNode = new Node(value);
                newNode.next = this.head;
                this.head = newNode;
            }

            insertAtTail(value) {
                const newNode = new Node(value);
                if (!this.head) {
                    this.head = newNode;
                    return;
                }
                let current = this.head;
                while (current.next) {
                    current = current.next;
                }
                current.next = newNode;
            }

            deleteByValue(value) {
                if (!this.head) return;  // Empty list
                if (this.head.value === value) {
                    this.head = this.head.next;
                    return;
                }
                let current = this.head;
                while (current.next) {
                    if (current.next.value === value) {
                        current.next = current.next.next;
                        return;
                    }
                    current = current.next;
                }
            }

            search(value) {
                let current = this.head;
                while (current) {
                    if (current.value === value) {
                        return current;  // Return the node for highlighting
                    }
                    current = current.next;
                }
                return null;  // Not found
            }

            // Helper to get array of values for rendering
            toArray() {
                const array = [];
                let current = this.head;
                while (current) {
                    array.push(current.value);
                    current = current.next;
                }
                return array;
            }
        }

