            if (isNaN(value)) {
                alert('Please enter a valid number.');
                return;
            }
            const foundNode = linkedList.search(value);
            if (foundNode) {
                renderLinkedList(value);  // Re-render with highlight
            } else {
                alert('Value not found in the list.');
                renderLinkedList();  // Re-render without highlight
            }
            document.getElementById('searchValue').value = '';  // Clear input
        }

        // Initial render for empty list
        renderLinkedList();
    </script>
